INSERT INTO psa_lessons (course_id, title, duration, has_homework, status, sort_order, content, summary, homework, cheatsheet) VALUES
  (1,'Роль мастера-приёмщика в автосервисе','45 min',true,'published',1,'Мастер-приёмщик — ключевая фигура автосервиса.','Мастер-приёмщик — лицо сервиса. Первое впечатление формируется в первые 30 секунд.','Опишите 3 ситуации из своей практики, когда первое впечатление определило исход визита клиента.','Формула: улыбка + имя клиента + зрительный контакт = доверие с первых секунд.'),
  (1,'Приём автомобиля: чек-лист осмотра','60 min',true,'published',2,'Правильный приём автомобиля — основа прозрачности сервиса.','Приём автомобиля всегда проводится вместе с клиентом.','Проведите 3 приёма по чек-листу и опишите реакцию клиентов.','Ключ: фотографируй каждый дефект ДО начала работ.'),
  (1,'Работа с клиентскими возражениями','50 min',true,'published',3,'Возражения клиента — запрос на дополнительную информацию.','Возражение — это не отказ, а запрос на информацию.','Запишите 5 возражений, которые вы слышали на этой неделе, и ваши ответы.','Метод ДДД: Да — Детали — Доводы'),
  (1,'Оформление заказ-наряда','40 min',false,'published',4,'Заказ-наряд — юридический документ.','Заказ-наряд — юридически значимый документ.','','Никогда не начинай работы без подписи клиента.'),
  (1,'Выдача автомобиля и постпродажный сервис','35 min',true,'draft',5,'Выдача — последний шанс сформировать лояльного клиента.','Выдача — финальный момент, который определяет вернётся ли клиент.','Опишите идеальный сценарий выдачи автомобиля клиенту.','Правило: клиент уходит с пониманием что сделано, что запланировано и когда звонить.'),
  (2,'Типология сложных клиентов','55 min',true,'published',1,'Сложные клиенты делятся на типы.','Агрессивный: не спорь. Тревожный: давай факты. Недоверчивый: показывай документы.','Опишите случай со сложным клиентом и как вы с ним справились.','Агрессивный: не спорь, дай выговориться. Тревожный: давай факты и цифры.'),
  (2,'Страховые и гарантийные случаи','70 min',true,'published',2,'Страховые случаи требуют строгого документального оформления.','Страховые случаи: фото — акт — согласование — работы.','Изучите порядок оформления страхового случая в вашем сервисе.','Главное: фото — акт — согласование — работы.'),
  (2,'Технический минимум для приёмщика','80 min',false,'draft',3,'Приёмщик обязан понимать основные узлы автомобиля.','ТО-1/ТО-2, тормозная система, подвеска, масла — минимум знаний.','','ТО-1/ТО-2, тормозная система, подвеска, масла — минимум знаний приёмщика.');
