INSERT INTO psa_homeworks (student_id, lesson_title, text, status, grade, trainer_comment) VALUES
  (2,'Приём автомобиля: чек-лист осмотра','Провёл 3 приёма по чек-листу. Клиенты охотнее соглашаются на доп.услуги когда видят письменный перечень нарушений.','pending',NULL,''),
  (3,'Роль мастера-приёмщика в автосервисе','Понял основное: мастер — это лицо сервиса. Применил на практике технику активного слушания.','checked',5,'Отличная работа!'),
  (4,'Работа с клиентскими возражениями','Попробовал метод. Работает не всегда, нужно больше практики.','revision',NULL,'Доработайте: опишите конкретные примеры.');
INSERT INTO psa_forum_topics (title, author_id, pinned, closed) VALUES
  ('Клиент говорит что масло меняли недавно а уровень критический',1,false,false),
  ('Как правильно объяснить клиенту необходимость дополнительных работ',2,false,false);
INSERT INTO psa_forum_posts (topic_id, author_id, text) VALUES
  (1,1,'Коллеги, разбираем на примере: клиент приезжает, говорит что масло меняли 2 месяца назад, а по щупу уровень критический. Как будете действовать?'),
  (1,2,'Сначала попрошу ключи, проверю пробег по одометру. Если пробег большой — предложу дополнительную диагностику.'),
  (1,4,'Я бы ещё проверил наличие подтёков снизу. Часто бывает, что масло уходит из-за прокладки клапанной крышки.'),
  (2,2,'Столкнулся с ситуацией: клиент сдаёт машину на ТО, нахожу изношенные тормозные колодки. Как убедить его заменить сейчас?'),
  (2,1,'Ключ — показать, а не рассказать. Предложите клиенту пройти с вами к машине и посмотреть самому.');